solution = ["__global__ or \n// __device__ function, just replace code like this:\n//\n//\n//  template<class T>\n//  __global__ void\n//  foo( T* g_idata, T* g_odata) \n//  {\n//      // Shared mem size is determined by the host app at run time\n//      extern __shared__  T sdata[];\n//      ...\n//      doStuff(sdata);\n//      ...\n//   }\n//  \n//   With this\n//  template<class T>\n//  __global__ void\n//  foo( T* g_idata, T* g_odata) \n//  {\n//      // Shared mem size is determined by the host app at run time\n//      SharedMemory<T> smem;\n//      T* sdata = smem.getPointer();\n//      ...\n//      doStuff(sdata);\n//      ...\n//   }\n//****************************************************************************\n\n// This is the un-specialized struct.  Note that we prevent instantiation of this \n// struct by putting an undefined symbol in the function body so it won't compile.\ntemplate <typename T>\nstruct SharedMemory\n{\n    // Ensure that we won't compile any un-specialized types\n    __device__ T* getPointer() {\n        extern __device__ void error(void);\n        error();\n        return NULL;\n    }", "__global__ void\n//  foo( T* g_idata, T* g_odata) \n//  {\n//      // Shared mem size is determined by the host app at run time\n//      extern __shared__  T sdata[];\n//      ...\n//      doStuff(sdata);\n//      ...\n//   }\n//  \n//   With this\n//  template<class T>\n//  __global__ void\n//  foo( T* g_idata, T* g_odata) \n//  {\n//      // Shared mem size is determined by the host app at run time\n//      SharedMemory<T> smem;\n//      T* sdata = smem.getPointer();\n//      ...\n//      doStuff(sdata);\n//      ...\n//   }\n//****************************************************************************\n\n// This is the un-specialized struct.  Note that we prevent instantiation of this \n// struct by putting an undefined symbol in the function body so it won't compile.\ntemplate <typename T>\nstruct SharedMemory\n{\n    // Ensure that we won't compile any un-specialized types\n    __device__ T* getPointer() {\n        extern __device__ void error(void);\n        error();\n        return NULL;\n    }", "__global__ void\n//  foo( T* g_idata, T* g_odata) \n//  {\n//      // Shared mem size is determined by the host app at run time\n//      SharedMemory<T> smem;\n//      T* sdata = smem.getPointer();\n//      ...\n//      doStuff(sdata);\n//      ...\n//   }\n//****************************************************************************\n\n// This is the un-specialized struct.  Note that we prevent instantiation of this \n// struct by putting an undefined symbol in the function body so it won't compile.\ntemplate <typename T>\nstruct SharedMemory\n{\n    // Ensure that we won't compile any un-specialized types\n    __device__ T* getPointer() {\n        extern __device__ void error(void);\n        error();\n        return NULL;\n    }"]
